    if (
      method === 'POST' &&
      url.pathname ===
        `/api/projects/${args.surface.project.projectId}/processes/${args.surface.process.processId}/${args.action}`
    ) {
      return buildJsonResponse(args.actionResponse);
    }

    throw new Error(
      `Unexpected fetch request in process-work-surface-page test: ${method} ${url.pathname}`,
    );
  });

  vi.stubGlobal('fetch', fetchMock);
  return fetchMock;
}

async function renderInteractiveProcessSurface(startUrl: string) {
  const dom = new JSDOM('<!doctype html><html><body><div id="app"></div></body></html>', {
    url: startUrl,
  });
  const url = new URL(startUrl);

  (dom.window as unknown as Window & typeof globalThis).__SHELL_BOOTSTRAP__ =
    shellBootstrapPayloadSchema.parse({
      actor: {
        id: 'user:workos-user-1',
        email: 'lee@example.com',
        displayName: 'Lee Moore',
      },
      pathname: url.pathname,
      search: url.search,
      csrfToken: 'csrf-token',
      auth: {
        loginPath: '/auth/login',
        logoutPath: '/auth/logout',
      },
    });

  await bootstrapApp(dom.window as unknown as Window & typeof globalThis);
  await flush();

  return dom;
}

